import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, CircularProgress } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Task {
  title: string;
  priority: string;
  completed: boolean;
}

interface TaskData {
  date: string;
  tasks: Task[];
  completionProgress: {
    totalTasks: number;
    completedTasks: number;
    percentage: number;
  };
}

export default function Widget() {
  const taskData = response.data as TaskData;
  const { tasks, completionProgress } = taskData;
  const theme = response.meta.theme;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#34A853' }}>
              Task Manager
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {taskData.date}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {tasks.slice(0, 3).map((task, index) => (
              <Chip
                key={index}
                label={task.title}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: task.completed ? '#34A853' : '#FBBC05', color: '#FFFFFF' }}
              />
            ))}
          </Stack>

          <Box>
            <Typography variant="caption" color="text.secondary">
              Progress
            </Typography>
            <Stack direction="row" alignItems="center" spacing={1} sx={{ mt: 0.5 }}>
              <CircularProgress variant="determinate" value={completionProgress.percentage} size={24} sx={{ color: '#34A853' }} />
              <Typography variant="body2" fontWeight={500}>
                {completionProgress.completedTasks}/{completionProgress.totalTasks} tasks completed
              </Typography>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
